package assessment.manager.security;


import jakarta.ws.rs.core.Response;
import org.keycloak.OAuth2Constants;
import org.keycloak.admin.client.CreatedResponseUtil;
import org.keycloak.admin.client.Keycloak;
import org.keycloak.admin.client.KeycloakBuilder;
import org.keycloak.representations.idm.*;

import org.springframework.beans.factory.annotation.Value;
import org.springframework.stereotype.Service;

import java.util.Collections;

@Service
public class KeycloakUserService {

    @Value("${keycloak.auth-server-url}")
    private String serverUrl;

    @Value("${keycloak.realm}")
    private String realm;

    @Value("${keycloak.client-id}")
    private String clientId;

    @Value("${keycloak.username}")
    private String adminUsername;

    @Value("${keycloak.password}")
    private String adminPassword;

    public String createUser(String username, String email, String password) {
        try {
            // Connect to Keycloak as admin
            Keycloak keycloak = KeycloakBuilder.builder()
                    .serverUrl(serverUrl)
                    .realm("master")  // Admin login realm is usually "master"
                    .grantType(OAuth2Constants.PASSWORD)
                    .clientId(clientId)
                    .username(adminUsername)
                    .password(adminPassword)
                    .build();

            // Create a new user representation
            UserRepresentation user = new UserRepresentation();
            user.setEnabled(true);
            user.setUsername(username);
            user.setEmail(email);

            // Send the user creation request
            Response response = keycloak.realm(realm).users().create(user);

            // Handle error if user is not created
            if (response.getStatus() != 201) {
                return "Error creating user: " + response.getStatus();
            }

            // Get the new user's ID from the response
            String userId = CreatedResponseUtil.getCreatedId(response);

            // Set the password for the user
            CredentialRepresentation credentials = new CredentialRepresentation();
            credentials.setTemporary(false);
            credentials.setType(CredentialRepresentation.PASSWORD);
            credentials.setValue(password);

            keycloak.realm(realm).users().get(userId).resetPassword(credentials);

            // Assign a default role
            RoleRepresentation userRole = keycloak.realm(realm).roles().get("ROLE_USER").toRepresentation();
            keycloak.realm(realm).users().get(userId).roles().realmLevel().add(Collections.singletonList(userRole));

            return "User registered successfully!";

        } catch (Exception e) {
            return "Registration failed: " + e.getMessage();
        }
    }
}

