+package assessment.manager.service;
+
+import assessment.manager.dto.LoginResponse;
+import assessment.manager.security.KeycloakUserService;
+import org.springframework.beans.factory.annotation.Autowired;
+import org.springframework.beans.factory.annotation.Value;
+import org.springframework.http.*;
+import org.springframework.stereotype.Service;
+import org.springframework.util.LinkedMultiValueMap;
+import org.springframework.util.MultiValueMap;
+import org.springframework.web.client.RestTemplate;
+
+import java.util.Map;
+
+@Service
+public class AuthService {
+
+    @Autowired
+    private KeycloakUserService keycloakUserService;
+
+    @Value("${keycloak.auth-server-url}")
+    private String keycloakServerUrl;
+
+    @Value("${keycloak.realm}")
+    private String realm;
+
+    @Value("${keycloak.client-id}")
+    private String clientId;
+
+    private final RestTemplate restTemplate = new RestTemplate();
+
+    public LoginResponse login(String username, String password) {
+        String tokenUrl = keycloakServerUrl + "/realms/" + realm + "/protocol/openid-connect/token";
+
+        HttpHeaders headers = new HttpHeaders();
+        headers.setContentType(MediaType.APPLICATION_FORM_URLENCODED);
+
+        MultiValueMap<String, String> map = new LinkedMultiValueMap<>();
+        map.add("grant_type", "password");
+        map.add("client_id", clientId);
+        map.add("username", username);
+        map.add("password", password);
+
+        HttpEntity<MultiValueMap<String, String>> request = new HttpEntity<>(map, headers);
+
+        try {
+            ResponseEntity<Map> response = restTemplate.postForEntity(tokenUrl, request, Map.class);
+            Map<String, Object> responseBody = response.getBody();
+
+            if (responseBody != null) {
+                String accessToken = (String) responseBody.get("access_token");
+                String refreshToken = (String) responseBody.get("refresh_token");
+                return new LoginResponse(accessToken, refreshToken, "Login successful");
+            }
+        } catch (Exception e) {
+            throw new RuntimeException("Invalid credentials", e);
+        }
+
+        throw new RuntimeException("Login failed");
+    }
+
+    public String registerUser(String username, String email, String password, String role) {
+        String result = keycloakUserService.createUser(username, email, password);
+        
+        if (result.contains("successfully")) {
+            // Additional logic to assign specific roles based on the role parameter
+            // This would involve calling Keycloak API to assign roles
+            return "User registered successfully with role: " + role;
+        }
+        
+        return result;
+    }
+
+    public void logout(String token) {
+        String logoutUrl = keycloakServerUrl + "/realms/" + realm + "/protocol/openid-connect/logout";
+
+        HttpHeaders headers = new HttpHeaders();
+        headers.setContentType(MediaType.APPLICATION_FORM_URLENCODED);
+        headers.setBearerAuth(token);
+
+        MultiValueMap<String, String> map = new LinkedMultiValueMap<>();
+        map.add("client_id", clientId);
+        map.add("refresh_token", token);
+
+        HttpEntity<MultiValueMap<String, String>> request = new HttpEntity<>(map, headers);
+
+        try {
+            restTemplate.postForEntity(logoutUrl, request, String.class);
+        } catch (Exception e) {
+            throw new RuntimeException("Logout failed", e);
+        }
+    }
+
+    public LoginResponse refreshToken(String refreshToken) {
+        String tokenUrl = keycloakServerUrl + "/realms/" + realm + "/protocol/openid-connect/token";
+
+        HttpHeaders headers = new HttpHeaders();
+        headers.setContentType(MediaType.APPLICATION_FORM_URLENCODED);
+
+        MultiValueMap<String, String> map = new LinkedMultiValueMap<>();
+        map.add("grant_type", "refresh_token");
+        map.add("client_id", clientId);
+        map.add("refresh_token", refreshToken);
+
+        HttpEntity<MultiValueMap<String, String>> request = new HttpEntity<>(map, headers);
+
+        try {
+            ResponseEntity<Map> response = restTemplate.postForEntity(tokenUrl, request, Map.class);
+            Map<String, Object> responseBody = response.getBody();
+
+            if (responseBody != null) {
+                String newAccessToken = (String) responseBody.get("access_token");
+                String newRefreshToken = (String) responseBody.get("refresh_token");
+                return new LoginResponse(newAccessToken, newRefreshToken, "Token refreshed successfully");
+            }
+        } catch (Exception e) {
+            throw new RuntimeException("Token refresh failed", e);
+        }
+
+        throw new RuntimeException("Token refresh failed");
+    }
+}

